mapper.select:
SELECT
FROM tb_mbm_user u LEFT JOIN tb_mbm_point p ON u.id = p.user_id LEFT JOIN tb_mbm_point_npay n ON p.id = n.point_id
ORDER BY n.partner_tx_no DESC, n.id DESC LIMIT #{offset}, #{recordSize}

mapper.update:
		UPDATE tb_mbm_point_npay
		SET	
 			 npay_api_type          = #{npayApiType				}
			,memo                   = #{memo			}
			,modified_date          = NOW()
			,modified_id            = #{modifiedId			}
		WHERE id = #{id}
